### 9. Routes Registration and Implementation

#### src/routes/posts.ts

```typescript
import { Router } from "express";
import { posts, nextId } from "../db.js";
import { Post } from "../types.js";

const router = Router();

// GET /posts - list all posts
router.get("/", (req, res) => {
  res.json(posts);
});

// GET /posts/:id - get a single post
router.get("/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const post = posts.find((p) => p.id === id);
  if (!post) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  res.json(post);
});

// POST /posts - create a new post
router.post("/", (req, res) => {
  const { title, content, userId } = req.body;
  if (!title || !content) {
    res.status(400).json({ error: "title and content are required" });
    return;
  }
  const newPost: Post = {
    id: nextId(posts),
    title,
    content,
    userId: userId || 1,
    createdAt: new Date().toISOString(),
  };
  posts.push(newPost);
  res.status(201).json(newPost);
});

// PUT /posts/:id - update a post
router.put("/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  const { title, content } = req.body;
  if (title) posts[index].title = title;
  if (content) posts[index].content = content;
  res.json(posts[index]);
});

// DELETE /posts/:id - delete a post
router.delete("/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  const deleted = posts.splice(index, 1);
  res.json(deleted[0]);
});

export { router as postsRouter };
```

**Routes Registered Under /posts:**
- `GET /posts/` - List all posts
- `GET /posts/:id` - Get single post by ID
- `POST /posts/` - Create new post (requires title, content; userId optional, defaults to 1)
- `PUT /posts/:id` - Update post title/content
- `DELETE /posts/:id` - Delete post

#### src/routes/comments.ts

```typescript
import { Router } from "express";
import { comments, posts, nextId } from "../db.js";
import { Comment } from "../types.js";

const router = Router();

// GET /posts/:postId/comments - list all comments for a post
router.get("/posts/:postId/comments", (req, res) => {
  const postId = parseInt(req.params.postId, 10);
  const post = posts.find((p) => p.id === postId);
  if (!post) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  const postComments = comments.filter((c) => c.postId === postId);
  res.json(postComments);
});

// GET /comments/:id - get a single comment
router.get("/comments/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const comment = comments.find((c) => c.id === id);
  if (!comment) {
    res.status(404).json({ error: "Comment not found" });
    return;
  }
  res.json(comment);
});

// POST /posts/:postId/comments - create a comment on a post
router.post("/posts/:postId/comments", (req, res) => {
  const postId = parseInt(req.params.postId, 10);
  const post = posts.find((p) => p.id === postId);
  if (!post) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  const { body, userId } = req.body;
  if (!body) {
    res.status(400).json({ error: "body is required" });
    return;
  }
  const newComment: Comment = {
    id: nextId(comments),
    postId,
    userId: userId || 1,
    body,
    createdAt: new Date().toISOString(),
  };
  comments.push(newComment);
  res.status(201).json(newComment);
});

// PUT /comments/:id - update a comment
router.put("/comments/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = comments.findIndex((c) => c.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Comment not found" });
    return;
  }
  const { body } = req.body;
  if (body) comments[index].body = body;
  res.json(comments[index]);
});

// DELETE /comments/:id - delete a comment
router.delete("/comments/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = comments.findIndex((c) => c.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Comment not found" });
    return;
  }
  const deleted = comments.splice(index, 1);
  res.json(deleted[0]);
});

export { router as commentsRouter };
```

**Routes Registered Without Prefix:**
- `GET /posts/:postId/comments` - Get all comments for a post
- `GET /comments/:id` - Get single comment by ID
- `POST /posts/:postId/comments` - Create new comment (requires body; userId optional, defaults to 1)
- `PUT /comments/:id` - Update comment body
- `DELETE /comments/:id` - Delete comment

### 10. How Routes Are Registered in app.ts

In `/src/app.ts`, routes are registered using:

```typescript
app.use("/posts", postsRouter);      // Posts endpoints under /posts prefix
app.use(commentsRouter);             // Comments endpoints at root (already have /posts/:id/comments paths)
```

This creates a two-tier routing structure:
1. **Posts Router** mounted at `/posts` prefix
   - Individual endpoints: `/`, `/:id`, `/:id` (PUT/DELETE), `:id` (POST)
   - Full paths: `GET /posts`, `GET /posts/1`, `POST /posts`, `PUT /posts/1`, `DELETE /posts/1`

2. **Comments Router** mounted at root but defines full paths internally
   - Full paths: `GET /posts/1/comments`, `POST /posts/1/comments`, `GET /comments/1`, `PUT /comments/1`, `DELETE /comments/1`

### 11. Test Files Overview

**tests/posts.test.ts** - Tests basic POST endpoints:
- GET /posts returns all posts
- GET /posts/:id returns single post with correct shape
- GET /health returns ok status

**tests/comments.test.ts** - Tests comment endpoints:
- GET /posts/:postId/comments returns comments for a post
- GET /posts/:postId/comments returns 404 for non-existent post
- GET /comments/:id returns single comment
- GET /comments/:id returns 404 for non-existent comment

**tests/auth.test.ts** - Comprehensive authentication tests:
- Registration (POST /auth/register) - Creates user, returns JWT token
- Login (POST /auth/login) - Validates credentials, returns token
- Protected routes - POST/PUT/DELETE require tokens
- Public routes - GET remains accessible without token
- Ownership - Users can only modify their own posts/comments
- Note: These tests reference auth endpoints that don't exist in current code (this is likely the task to be completed)

