**POST /register:**
- Validate `username`, `email`, `password` all present → `400` if not
- Check for duplicate `username` → `409` if found
- Hash the password, push new user to `users` array using `nextId(users)`
- Sign JWT with `{ id, username }` and `JWT_SECRET`
- Return `201` with `{ token, user: { id, username, email } }` — **omit password**

**POST /login:**
- Find user by `username` → `401` if not found
- Hash provided password and compare to stored hash → `401` if mismatch
- Sign and return `200` with `{ token }`

```ts
// src/routes/auth.ts
import { Router } from "express";
import { createHash } from "crypto";
import jwt from "jsonwebtoken";
import { users, nextId } from "../db.js";
import { JWT_SECRET } from "../middleware/auth.js";

const router = Router();

function hashPassword(password: string): string {
  return createHash("sha256").update(password).digest("hex");
}

router.post("/register", (req, res) => {
  const { username, email, password } = req.body;
  if (!username || !email || !password) {
    res.status(400).json({ error: "username, email, and password are required" });
    return;
  }
  if (users.find(u => u.username === username)) {
    res.status(409).json({ error: "Username already taken" });
    return;
  }
  const newUser = { id: nextId(users), username, email, password: hashPassword(password) };
  users.push(newUser);
  const token = jwt.sign({ id: newUser.id, username: newUser.username }, JWT_SECRET);
  res.status(201).json({ token, user: { id: newUser.id, username, email } });
});

router.post("/login", (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username);
  if (!user || user.password !== hashPassword(password)) {
    res.status(401).json({ error: "Invalid credentials" });
    return;
  }
  const token = jwt.sign({ id: user.id, username: user.username }, JWT_SECRET);
  res.status(200).json({ token });
});

export { router as authRouter };
```

